const deviceId = msg.topic.split('/')[1];
let status = msg.payload;
if (typeof status === 'string') {
  try { status = JSON.parse(status).status; } catch (e) { /* plain string */ }
} else if (status && typeof status === 'object') {
  status = status.status;
}
const isOnline = status === 'online';
msg.headers = {
  'Content-Type': 'application/json',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY'),
};
msg.method = 'POST';
msg.url = env.get('SUPABASE_REST') + '/rpc/set_device_status';
msg.payload = {
  p_device_id: deviceId,
  p_is_online: isOnline,
};
return msg;

const deviceId = msg.topic.split('/')[1];
let data = msg.payload;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch (e) { data = { value: data }; }
}
if (typeof data !== 'object' || data === null) {
  data = { value: data };
}
const headers = {
  'Content-Type': 'application/json',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY'),
};
const telem = {
  headers,
  method: 'POST',
  url: env.get('SUPABASE_REST') + '/telemetry',
  payload: [{ device_id: deviceId, topic: msg.topic, payload: data }],
};
const touch = {
  headers,
  method: 'POST',
  url: env.get('SUPABASE_REST') + '/rpc/touch_device',
  payload: { p_device_id: deviceId },
};
return [telem, touch];

const deviceId = msg.topic.split('/')[1];
let capabilities = msg.payload;
if (typeof capabilities === 'string') {
  try { capabilities = JSON.parse(capabilities); } catch (e) { return null; }
}
if (!capabilities || !capabilities.commands || !Array.isArray(capabilities.commands)) {
  return null;
}
msg.headers = {
  'Content-Type': 'application/json',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY'),
};
msg.method = 'POST';
msg.url = env.get('SUPABASE_REST') + '/rpc/merge_device_commands';
msg.payload = {
  p_device_id: deviceId,
  p_commands: capabilities.commands,
  p_metrics: Array.isArray(capabilities.metrics) ? capabilities.metrics : null,
  p_dashboard: capabilities.dashboard && typeof capabilities.dashboard === 'object' ? capabilities.dashboard : null,
};
return msg;
